// Turn every FAQ row into a numbered Q/A block for the LLM.
// Flexible about column names so it works with most spreadsheet layouts.
const rows = $input.all().map(i => i.json);

function pick(row, keys) {
  for (const k of Object.keys(row)) {
    const norm = k.toLowerCase().trim();
    if (keys.includes(norm)) return row[k];
  }
  return undefined;
}

const faqText = rows.map((r, idx) => {
  const cat = pick(r, ['category', 'topic', 'type']);
  const q = pick(r, ['question', 'query', 'q', 'questions']) ?? Object.values(r)[0];
  const a = pick(r, ['answer', 'response', 'a', 'answers']) ?? Object.values(r)[1];
  const catStr = cat ? ` [${cat}]` : '';
  return `${idx + 1}.${catStr} Q: ${q}\n   A: ${a}`;
}).join('\n');

const prep = $('Prepare Input').first().json;

return [{
  json: {
    faqText: faqText || 'No FAQ rows were found in the spreadsheet.',
    faqRowCount: rows.length,
    query: prep.query,
    learnerName: prep.learnerName,
    learnerEmail: prep.learnerEmail,
    sessionId: prep.sessionId,
    timestamp: prep.timestamp
  }
}];

